from pydantic import BaseModel, Field from typing import List
class Entity(BaseModel): name: str = Field(description="Entity name as it appears in the text") type: str = Field(description="Entity type: person, company, location, or product") confidence: float = Field(ge=0, le=1, description="Confidence score 0.0-1.0")
class ExtractionResult(BaseModel): entities: List[Entity] summary: str = Field(description="One sentence summary of the text") language: str = Field(description="ISO 639-1 language code, e.g., 'en'")

import json
import anthropic
from pydantic import BaseModel, ValidationError

client = anthropic.Anthropic()

def extract_claude(text: str, model_cls: type[BaseModel], max_retries=2) -> BaseModel:
    schema = json.dumps(model_cls.model_json_schema(), indent=2)
    prompt = f"Return JSON matching this schema:\n{schema}\n\nText:\n{text}"

    for attempt in range(max_retries + 1):
        resp = client.messages.create(
            model="claude-sonnet-4-20250514",
            max_tokens=1024,
            messages=[{"role": "user", "content": prompt}]
        )
        raw = resp.content[0].text.strip()
        # Strip markdown code fences
        if raw.startswith("```"):
            raw = raw.split("```")[1].lstrip("json").strip()
        try:
            return model_cls.model_validate_json(raw)
        except (json.JSONDecodeError, ValidationError) as e:
            if attempt == max_retries:
                raise
            prompt = f"The JSON was invalid: {e}\n\nFix and return only valid JSON."
    raise RuntimeError("unreachable")

def extract_via_tool(prompt: str, schema: dict, client, model="gpt-4o") -> dict:
    """Force structured output via function calling — works on any OpenAI model."""
    import json
    tools = [{"type": "function", "function": {
        "name": "output", "description": "Return result", "parameters": schema
    }}]
    resp = client.chat.completions.create(
        model=model, messages=[{"role": "user", "content": prompt}],
        tools=tools, tool_choice={"type": "function", "function": {"name": "output"}}
    )
    return json.loads(resp.choices[0].message.tool_calls[0].function.arguments)
